const response = JSON.parse($input.first().json.body);
const text = response.content[0].text;
let parsed;
try {
  const clean = text.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = { score: 0, apply: false, variant: 'backend', summary: text, red_flags: 'parse error' };
}
return [{ json: { ...parsed, row_id: $input.first().json.row_id, jd_text: $input.first().json.jd_text, company: $input.first().json.company, title: $input.first().json.title, jd_url: $input.first().json.jd_url } }];

